vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 d = uTexSize.zw*vRadius;
    vec3 dx = ( GetBlur1(vUv+vec2(3,0)*d*3)-GetBlur1(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(vUv+vec2(0,1)*d*10)-GetBlur1(vUv-vec2(0,1)*d) );

vec2 uv_x = vRadius - vec2(dx.y,dy.y)*vRadius + vec2(dx.z,dy.z)*0.02;
ret = GetBlur2(uv_x).x*clamp01(1-GetPixel(vUv).y)*pow(hue_shader.yxz,8)*3;
ret = mix(ret,pow(hue_shader.yzx,12)*1.4,GetPixel(uv_x).x*1.8 + GetBlur1(uv_x).x);
ret *= clamp01(1 - GetBlur1(vUv).z*8);
ret *= mix(ret,1,pow(hue_shader,4)*GetPixel(clamp01(vUv - vec2(dx.z,dy.z)*2)).y*1.2);
ret = mix(ret,pow(hue_shader,4).zxy*1.8,GetPixel(vUv).z);

  fragColor = ret;
}
